-- Module de questions : Recrutement Instructeur — MIXOU AIRLINES PTFS (40 questions)
INSERT INTO aeroschool_question_modules (title, questions)
VALUES (
  'Recrutement Instructeur — MIXOU AIRLINES PTFS',
  '[
    {"id":"q1","title":"Quel est le rôle principal d''un Instructeur sur le serveur MIXOU AIRLINES PTFS ?","options":["A) Sanctionner les membres ne respectant pas les règles","B) Accompagner, orienter et former les membres de la communauté","C) Gérer les litiges entre membres","D) Administrer les canaux du serveur"],"correct_answers":["B) Accompagner, orienter et former les membres de la communauté"]},
    {"id":"q2","title":"Un Instructeur dispose-t-il d''un pouvoir disciplinaire sur le serveur ?","options":["A) Oui, il peut prononcer des avertissements écrits","B) Oui, mais uniquement dans le cadre du Roleplay","C) Oui, avec l''accord d''un modérateur","D) Non, il ne peut en aucun cas prononcer de sanctions"],"correct_answers":["D) Non, il ne peut en aucun cas prononcer de sanctions"]},
    {"id":"q3","title":"Un membre perturbe un cours en vocal que tu dispenses. Quelle est la bonne réaction ?","options":["A) Le sanctionner immédiatement","B) Ignorer le comportement et continuer le cours","C) Signaler le comportement à la Modération ou à l''Administration","D) Expulser le membre du canal vocal toi-même"],"correct_answers":["C) Signaler le comportement à la Modération ou à l''Administration"]},
    {"id":"q4","title":"Un nouveau membre te pose une question relative à une sanction disciplinaire qu''il a reçue. Que fais-tu ?","options":["A) Tu lui expliques comment contester la sanction","B) Tu annules la sanction si tu la juges injuste","C) Tu le rediriges vers un membre de la Modération compétent","D) Tu ignores sa question car ce n''est pas ton rôle"],"correct_answers":["C) Tu le rediriges vers un membre de la Modération compétent"]},
    {"id":"q5","title":"Durant un cours en vocal, un élève souhaite poser une question. Comment doit-il procéder ?","options":["A) Il peut parler librement à tout moment","B) Il envoie sa question dans le salon textuel sans demander la parole","C) Il utilise la fonctionnalité de lever la main sur Discord et attend que la parole lui soit accordée","D) Il attend la fin du cours pour contacter l''instructeur en message privé"],"correct_answers":["C) Il utilise la fonctionnalité de lever la main sur Discord et attend que la parole lui soit accordée"]},
    {"id":"q6","title":"Quel est le statut hiérarchique des Instructeurs au sein de la direction de MIXOU AIRLINES PTFS ?","options":["A) Ils sont au même niveau que la Modération","B) Ils sont au-dessus du Staff Stagiaire mais en dessous de l''Administration","C) Ils sont assimilés au statut de helpers et constituent le dernier échelon de la hiérarchie","D) Ils n''appartiennent pas à la direction du serveur"],"correct_answers":["C) Ils sont assimilés au statut de helpers et constituent le dernier échelon de la hiérarchie"]},
    {"id":"q7","title":"Par qui les Instructeurs sont-ils nommés ?","options":["A) Par les Fondateurs uniquement","B) Par un vote de la communauté","C) Par l''Administration sur la base de leurs connaissances, de leur pédagogie et de leur investissement","D) Par la Modération après une période de stage"],"correct_answers":["C) Par l''Administration sur la base de leurs connaissances, de leur pédagogie et de leur investissement"]},
    {"id":"q8","title":"Un élève rejoint ton salon de cours en vocal alors que la session est déjà commencée, sans t''avoir prévenu. Que fais-tu ?","options":["A) Tu continues le cours sans réagir","B) Tu lui donnes immédiatement un avertissement verbal","C) Tu peux l''expulser du salon pour intrusion non autorisée et en informer la Modération","D) Tu suspends le cours et recommences depuis le début pour l''élève arrivé en retard"],"correct_answers":["C) Tu peux l''expulser du salon pour intrusion non autorisée et en informer la Modération"]},
    {"id":"q9","title":"Quelle balise est utilisée dans un salon RP pour indiquer un message Hors Roleplay ?","options":["A) [[ message HRP ]]","B) // message HRP //","C) (( message HRP ))","D) ## message HRP ##"],"correct_answers":["C) (( message HRP ))"]},
    {"id":"q10","title":"Un membre te contacte pour obtenir des informations sur une affaire en cours devant la Cour Suprême. Que fais-tu ?","options":["A) Tu lui communiques les informations disponibles pour l''aider","B) Tu lui conseilles de contacter directement le Juge Principal","C) Tu lui rappelles que les procédures de la Cour Suprême sont strictement confidentielles","D) Tu transmets sa demande à l''Administration pour qu''elle réponde"],"correct_answers":["C) Tu lui rappelles que les procédures de la Cour Suprême sont strictement confidentielles"]},
    {"id":"q11","title":"Quel organisme est compétent pour traiter un litige survenu exclusivement dans le cadre du Roleplay ?","options":["A) La Cour Suprême","B) L''Administration","C) Le Tribunal Administratif","D) La Modération"],"correct_answers":["C) Le Tribunal Administratif"]},
    {"id":"q12","title":"Un cours en vocal vient de se terminer. Un membre te demande l''autorisation d''enregistrer et de partager le contenu de la session. Que réponds-tu ?","options":["A) Tu acceptes car cela peut aider d''autres membres","B) Tu acceptes uniquement si le membre est Staff Stagiaire","C) Tu refuses car l''enregistrement et le partage nécessitent une autorisation explicite du staff","D) Tu acceptes à condition que l''enregistrement ne soit partagé qu''en privé"],"correct_answers":["C) Tu refuses car l''enregistrement et le partage nécessitent une autorisation explicite du staff"]},
    {"id":"q13","title":"Quelle est la définition du ping spam selon le Code de Conduite de MIXOU AIRLINES PTFS ?","options":["A) L''envoi de messages répétés dans un salon textuel","B) L''utilisation abusive du rôle @everyone","C) Le ping excessif ou répété d''un même membre dans un court laps de temps","D) L''envoi de notifications de rôles sans autorisation"],"correct_answers":["C) Le ping excessif ou répété d''un même membre dans un court laps de temps"]},
    {"id":"q14","title":"Un membre du serveur adopte un comportement de trolling durant une opération RP. En tant qu''Instructeur, que fais-tu ?","options":["A) Tu mutes le membre directement","B) Tu ignores le comportement s''il ne perturbe pas directement ton cours","C) Tu signales immédiatement le comportement à la Modération sans intervenir toi-même","D) Tu exclus le membre de l''opération en cours"],"correct_answers":["C) Tu signales immédiatement le comportement à la Modération sans intervenir toi-même"]},
    {"id":"q15","title":"Combien d''avertissements écrits RP sont nécessaires pour déclencher automatiquement un blâme RP ?","options":["A) Deux","B) Trois","C) Quatre","D) Cinq"],"correct_answers":["B) Trois"]},
    {"id":"q16","title":"Durant une session d''instructions en vocal, un membre interrompt la personne habilitée en train de délivrer les consignes. Ce comportement est-il sanctionnable ?","options":["A) Non, si l''interruption est brève","B) Non, si le membre pose une question pertinente","C) Oui, toute interruption non autorisée durant une session d''instructions est sanctionnable","D) Oui, mais uniquement si l''interruption se répète plus de deux fois"],"correct_answers":["C) Oui, toute interruption non autorisée durant une session d''instructions est sanctionnable"]},
    {"id":"q17","title":"Quel est le délai maximum dont dispose un membre pour former un appel devant la Cour Suprême après notification d''une décision du Tribunal Administratif ?","options":["A) 24 heures","B) 48 heures","C) 72 heures","D) Une semaine"],"correct_answers":["B) 48 heures"]},
    {"id":"q18","title":"Un élève utilise un microphone de mauvaise qualité générant des nuisances sonores persistantes malgré tes remarques. Que peux-tu faire ?","options":["A) Continuer le cours en ignorant les nuisances","B) Annuler la session de cours","C) Alerter la Modération pour qu''elle intervienne et mute le membre concerné","D) Donner un avertissement écrit au membre toi-même"],"correct_answers":["C) Alerter la Modération pour qu''elle intervienne et mute le membre concerné"]},
    {"id":"q19","title":"Qu''est-ce qu''un salon vocal Fréquence sur MIXOU AIRLINES PTFS ?","options":["A) Un salon de détente réservé aux membres du staff","B) Un salon dédié aux cours de formation des nouveaux membres","C) Un espace dédié aux communications officielles simulant un environnement de communication aéronautique","D) Un salon libre accessible à tous les membres sans restriction"],"correct_answers":["C) Un espace dédié aux communications officielles simulant un environnement de communication aéronautique"]},
    {"id":"q20","title":"Un membre souhaite faire de la publicité pour un autre serveur Discord dans un salon HRP. Est-ce autorisé ?","options":["A) Oui, à condition que le serveur soit lié à l''aviation","B) Oui, si le message est posté dans le bon salon","C) Oui, avec l''accord d''un autre membre","D) Non, toute publicité extérieure est strictement interdite sans autorisation préalable du staff"],"correct_answers":["D) Non, toute publicité extérieure est strictement interdite sans autorisation préalable du staff"]},
    {"id":"q21","title":"Un Instructeur peut-il assister à une délibération de la Cour Suprême ?","options":["A) Oui, s''il est convoqué comme témoin","B) Oui, avec l''accord du Juge Principal","C) Non, les délibérations de la Cour Suprême sont strictement réservées à ses membres","D) Oui, en tant qu''observateur neutre"],"correct_answers":["C) Non, les délibérations de la Cour Suprême sont strictement réservées à ses membres"]},
    {"id":"q22","title":"Qu''est-ce que le RP de mauvaise foi ?","options":["A) Un roleplay effectué dans le mauvais salon","B) Un roleplay sans licence valide","C) Un comportement de jeu jugé incohérent, absurde ou visant à perturber le bon déroulement d''un scénario","D) Un roleplay impliquant des personnages fictifs non autorisés"],"correct_answers":["C) Un comportement de jeu jugé incohérent, absurde ou visant à perturber le bon déroulement d''un scénario"]},
    {"id":"q23","title":"Quelle instance juridique constitue la juridiction souveraine et de dernier ressort de MIXOU AIRLINES PTFS ?","options":["A) Le Tribunal Administratif","B) L''Administration","C) La Cour Suprême","D) Les Fondateurs réunis en conseil"],"correct_answers":["C) La Cour Suprême"]},
    {"id":"q24","title":"Quel comportement est strictement interdit dans les salons vocaux Chill ?","options":["A) Utiliser un soundboard de manière modérée","B) Discuter de sujets non liés aux opérations","C) Monopoliser le salon en restant muet de manière prolongée pour en empêcher l''accès à d''autres membres","D) Écouter de la musique à faible volume"],"correct_answers":["C) Monopoliser le salon en restant muet de manière prolongée pour en empêcher l''accès à d''autres membres"]},
    {"id":"q25","title":"Un Instructeur constate qu''un membre simule un incident terroriste lors d''une opération RP. Quelle est la bonne conduite à tenir ?","options":["A) Ignorer l''incident s''il reste dans le cadre fictif du RP","B) Avertir verbalement le membre et continuer l''opération","C) Signaler immédiatement l''incident à la Modération car cette simulation est strictement interdite par le Code de Conduite","D) Mettre fin à l''opération de sa propre initiative"],"correct_answers":["C) Signaler immédiatement l''incident à la Modération car cette simulation est strictement interdite par le Code de Conduite"]},
    {"id":"q26","title":"Dans quel délai le Juge Principal doit-il examiner la recevabilité d''une saisine de la Cour Suprême ?","options":["A) 24 heures","B) 48 heures","C) 72 heures","D) 7 jours"],"correct_answers":["B) 48 heures"]},
    {"id":"q27","title":"Un membre du Collège Juridique refuse de voter lors d''une délibération. Que risque-t-il ?","options":["A) Un avertissement verbal","B) Une suspension temporaire de ses fonctions","C) Une révocation du Collège Juridique pour faute disciplinaire","D) Rien, l''abstention est tolérée en cas de doute"],"correct_answers":["C) Une révocation du Collège Juridique pour faute disciplinaire"]},
    {"id":"q28","title":"Quelle est la sanction RP la plus grave applicable à un membre à titre individuel ?","options":["A) La suspension RP","B) Le retrait définitif de licence","C) L''exclusion RP définitive avec réinitialisation complète du dossier RP","D) La rétrogradation RP au grade le plus bas"],"correct_answers":["C) L''exclusion RP définitive avec réinitialisation complète du dossier RP"]},
    {"id":"q29","title":"Un Instructeur peut-il modifier les paramètres des bots de modération Jean-Jacques et Wick ?","options":["A) Oui, en cas de raid imminent","B) Oui, avec l''accord de l''Administration","C) Non, la configuration de ces bots est réservée exclusivement aux Fondateurs et à l''Administration","D) Oui, uniquement pour les paramètres liés aux cours"],"correct_answers":["C) Non, la configuration de ces bots est réservée exclusivement aux Fondateurs et à l''Administration"]},
    {"id":"q30","title":"Quelle est la sanction ultime applicable à une compagnie dans le cadre du Roleplay ?","options":["A) La révocation de l''agrément","B) La suspension temporaire des activités","C) La mise sous administration provisoire","D) La dissolution forcée de la compagnie"],"correct_answers":["D) La dissolution forcée de la compagnie"]},
    {"id":"q31","title":"Un membre te demande pourquoi les Fondateurs ont pris une décision particulière concernant le serveur. Que lui réponds-tu ?","options":["A) Tu lui expliques les raisons de la décision si tu les connais","B) Tu lui conseilles de critiquer la décision publiquement","C) Tu lui expliques que les décisions des Fondateurs sont souveraines et tu l''invites à contacter le staff via le canal approprié s''il a des questions","D) Tu lui dis que les décisions des Fondateurs ne peuvent jamais être remises en question"],"correct_answers":["C) Tu lui expliques que les décisions des Fondateurs sont souveraines et tu l''invites à contacter le staff via le canal approprié s''il a des questions"]},
    {"id":"q32","title":"Combien d''avertissements écrits HRP déclenchent automatiquement un blâme HRP ?","options":["A) Deux","B) Trois","C) Cinq","D) Quatre"],"correct_answers":["B) Trois"]},
    {"id":"q33","title":"Quel principe garantit que chaque partie dans une procédure devant la Cour Suprême a accès aux pièces produites par la partie adverse ?","options":["A) Le principe de souveraineté","B) Le principe de proportionnalité","C) Le principe du contradictoire","D) Le principe d''impartialité"],"correct_answers":["C) Le principe du contradictoire"]},
    {"id":"q34","title":"Un membre Staff Stagiaire te demande de l''aide pour prendre une décision disciplinaire. Que lui conseilles-tu ?","options":["A) Tu lui indiques comment prononcer une sanction","B) Tu prends la décision à sa place","C) Tu lui rappelles qu''il doit en référer à un modérateur titulaire ou à l''Administration, et tu l''y rediriges","D) Tu lui dis d''attendre la fin de sa période de stage pour agir"],"correct_answers":["C) Tu lui rappelles qu''il doit en référer à un modérateur titulaire ou à l''Administration, et tu l''y rediriges"]},
    {"id":"q35","title":"Quelle est la différence entre un salon vocal Fréquence et un salon vocal dédié aux Instructions ?","options":["A) Il n''y a aucune différence, ce sont les mêmes espaces","B) Le salon Fréquence est réservé au staff, le salon Instructions est ouvert à tous","C) Le salon Fréquence est dédié aux communications opérationnelles, tandis que le salon Instructions est dédié à la transmission de consignes officielles en temps réel","D) Le salon Instructions est uniquement utilisé pour les cours de formation"],"correct_answers":["C) Le salon Fréquence est dédié aux communications opérationnelles, tandis que le salon Instructions est dédié à la transmission de consignes officielles en temps réel"]},
    {"id":"q36","title":"Qu''est-ce qu''une mise sous administration provisoire dans le cadre des sanctions RP d''une compagnie ?","options":["A) Une interdiction temporaire de recruter de nouveaux membres","B) Un gel des actifs financiers de la compagnie","C) Une mesure par laquelle le Tribunal Administratif ou l''Administration prend temporairement le contrôle de la gestion de la compagnie","D) Une suspension du dirigeant de la compagnie sans toucher à ses activités"],"correct_answers":["C) Une mesure par laquelle le Tribunal Administratif ou l''Administration prend temporairement le contrôle de la gestion de la compagnie"]},
    {"id":"q37","title":"Un membre non autorisé tente d''accéder à un salon vocal Fréquence en cours d''opération. Que fais-tu en tant qu''Instructeur ?","options":["A) Tu lui expliques les règles et le laisses rester discrètement","B) Tu l''expulses toi-même du salon","C) Tu signales immédiatement sa présence à la Modération pour qu''elle intervienne","D) Tu suspends l''opération jusqu''à son départ"],"correct_answers":["C) Tu signales immédiatement sa présence à la Modération pour qu''elle intervienne"]},
    {"id":"q38","title":"Quelles sont les trois issues possibles à l''issue de la période de stage du Staff Stagiaire ?","options":["A) Titularisation, exclusion temporaire ou reconduction automatique","B) Titularisation, prolongation du stage ou fin du stage","C) Titularisation, rétrogradation ou exclusion définitive","D) Prolongation du stage, accès au rang d''Instructeur ou exclusion"],"correct_answers":["B) Titularisation, prolongation du stage ou fin du stage"]},
    {"id":"q39","title":"Un membre te reproche publiquement dans un salon textuel une erreur commise lors d''un cours. Comment réagis-tu ?","options":["A) Tu réponds publiquement pour te défendre","B) Tu ignores le message","C) Tu invites le membre à te contacter en privé ou via le canal de signalement approprié, et tu en informes la Modération si nécessaire","D) Tu lui donnes raison publiquement pour éviter le conflit"],"correct_answers":["C) Tu invites le membre à te contacter en privé ou via le canal de signalement approprié, et tu en informes la Modération si nécessaire"]},
    {"id":"q40","title":"Quelle est la condition sine qua non pour qu''une décision de la Cour Suprême soit valablement rendue ?","options":["A) La présence de tous les membres du Collège Juridique","B) L''accord unanime de tous les membres votants","C) La réunion du quorum minimal composé du Juge Principal et d''au moins deux membres du Collège Juridique","D) La validation préalable des Fondateurs"],"correct_answers":["C) La réunion du quorum minimal composé du Juge Principal et d''au moins deux membres du Collège Juridique"]}
  ]'::jsonb
);
